evaluators.evaluation_logic:
const checkpoints = [];

const bots = JSON.parse(localStorage.getItem('bots') || '[]');
const channels = JSON.parse(localStorage.getItem('channels') || '[]');
const inboxes = JSON.parse(localStorage.getItem('inboxes') || '[]');
const targetingRules = JSON.parse(localStorage.getItem('targeting_rules') || '[]');
const conditionGroups = JSON.parse(localStorage.getItem('condition_groups') || '[]');
const conditions = JSON.parse(localStorage.getItem('conditions') || '[]');
const botFlowSteps = JSON.parse(localStorage.getItem('bot_flow_steps') || '[]');
const chatTemplates = JSON.parse(localStorage.getItem('chat_message_templates') || '[]');
const automations = JSON.parse(localStorage.getItem('automations') || '[]');
const automationActions = JSON.parse(localStorage.getItem('automation_actions') || '[]');

const activeWebsiteChannelIds = channels
  .filter(c => c && c.channel_type === 'website' && c.is_active)
  .map(c => c.id);

function hasUsTargeting(botId) {
  const rules = targetingRules.filter(r => r && r.bot_id === botId && r.is_active);
  if (!rules.length) return false;
  return rules.some(rule => {
    if (rule.base_audience !== 'new_visitors') return false;
    const groups = conditionGroups.filter(g => g && g.owner_type === 'targeting_rule' && g.owner_id === rule.id);
    return groups.some(g => {
      const conds = conditions.filter(c => c && c.owner_type === 'condition_group' && c.owner_id === g.id);
      return conds.some(c => c.field === 'country' && c.operator === 'equals' && c.value === 'United States');
    });
  });
}

function isLeadWebsiteBot(bot) {
  if (!bot) return false;
  if (bot.type !== 'website_chatbot') return false;
  if (!activeWebsiteChannelIds.includes(bot.channel_id)) return false;
  if (!bot.availability_enabled) return false;
  if (bot.timezone !== 'America/New_York') return false;
  if (!bot.show_to_new_visitors_only) return false;
  if (!(typeof bot.repeat_after_days === 'number' && bot.repeat_after_days >= 30)) return false;

  // Greeting must ask for full name, company, and work email
  const greet = (bot.greeting_message || '').toLowerCase();
  if (!(greet.includes('full name') && greet.includes('company') && greet.includes('work email'))) return false;

  // Weekday business hours roughly 09:00-17:00
  const daysNeeded = ['monday','tuesday','wednesday','thursday','friday'];
  const bh = Array.isArray(bot.business_hours) ? bot.business_hours : [];
  const hasAllWeekdays = daysNeeded.every(d =>
    bh.some(h => h.day_of_week === d && h.start_time === '09:00' && h.end_time === '17:00')
  );
  if (!hasAllWeekdays) return false;

  // Standard offline message: use default offline template
  const offlineTemplate = chatTemplates.find(t => t && t.id === bot.offline_message_template_id && t.template_type === 'offline');
  if (!offlineTemplate || offlineTemplate.is_default !== true) return false;

  // Audience must be US-only new visitors
  if (!hasUsTargeting(bot.id)) return false;

  return true;
}

const qualifyingLeadBots = bots.filter(isLeadWebsiteBot);
const primaryBot = qualifyingLeadBots[0] || null;

// CP1 (0.40): A website chatbot exists on an active website channel with US-only new-visitor targeting, correct greeting, NY weekday hours, and standard offline message.
checkpoints.push({ passed: !!primaryBot, weight: 0.40 });

function hasRequiredLeadFields(bot) {
  if (!bot) return false;
  const steps = botFlowSteps.filter(s => s && s.bot_id === bot.id);
  const lower = s => (s || '').toLowerCase();

  const fullNameOk = steps.some(s =>
    s.step_type === 'question' && s.required === true && s.field_key &&
    lower(s.field_key).includes('full') && lower(s.field_key).includes('name')
  );

  const companyOk = steps.some(s =>
    s.step_type === 'question' && s.required === true && s.field_key &&
    lower(s.field_key).includes('company')
  );

  const emailOk = steps.some(s =>
    s.step_type === 'question' && s.required === true && s.question_type === 'email'
  );

  return fullNameOk && companyOk && emailOk;
}

const leadFieldsOk = primaryBot ? hasRequiredLeadFields(primaryBot) : false;

// CP2 (0.30): The same bot's flow has required questions for full name, company, and work email.
checkpoints.push({ passed: leadFieldsOk, weight: 0.30 });

function hasHighBudgetRouting(bot) {
  if (!bot) return false;
  const salesInbox = inboxes.find(i => i && i.name && i.name.toLowerCase() === 'sales');
  if (!salesInbox) return false;

  // Prefer an automation that routes website_chat with budget > 5000 to Sales
  const candidateAutos = automations.filter(a => a && a.status === 'active' && a.trigger_type === 'new_conversation_created');

  const hasAutomation = candidateAutos.some(a => {
    const groups = conditionGroups.filter(g => g && g.owner_type === 'automation_rule' && g.owner_id === a.id);
    let hasWebsiteChannelCond = false;
    let hasBudgetCond = false;

    groups.forEach(g => {
      const conds = conditions.filter(c => c && c.owner_type === 'condition_group' && c.owner_id === g.id);
      conds.forEach(c => {
        if (c.field === 'channel' && c.operator === 'equals' && c.value === 'website_chat') {
          hasWebsiteChannelCond = true;
        }
        if ((c.field === 'budget_estimate' || c.field === 'budget') &&
            (c.operator === 'greater_than_or_equal' || c.operator === 'greater_than') &&
            typeof c.value === 'string' && parseFloat(c.value) >= 5000) {
          hasBudgetCond = true;
        }
      });
    });

    if (!(hasWebsiteChannelCond && hasBudgetCond)) return false;

    const acts = automationActions.filter(act => act && act.automation_rule_id === a.id);
    return acts.some(act => act.action_type === 'assign_inbox' && act.target_inbox_id === salesInbox.id);
  });

  if (hasAutomation) return true;

  // Fallback: check for bot-level condition_actions on a numeric budget question
  const steps = botFlowSteps.filter(s => s && s.bot_id === bot.id);
  return steps.some(s => {
    if (s.step_type !== 'question' || s.question_type !== 'numeric') return false;
    const text = ((s.label || '') + ' ' + (s.prompt_text || '')).toLowerCase();
    if (!text.includes('budget')) return false;
    const cas = Array.isArray(s.condition_actions) ? s.condition_actions : [];
    return cas.some(ca => {
      const op = ca.comparison_operator;
      const valNum = typeof ca.comparison_value === 'number' ? ca.comparison_value : parseFloat(ca.comparison_value || '');
      return (op === 'greater_than' || op === 'greater_than_or_equal') &&
             !isNaN(valNum) && valNum >= 5000 &&
             ca.action_type === 'assign_inbox' && ca.target_inbox_id === salesInbox.id;
    });
  });
}

const budgetRoutingOk = primaryBot ? hasHighBudgetRouting(primaryBot) : false;

// CP3 (0.30): The bot's flow and/or an automation routes conversations with estimated budget > $5,000 to the Sales inbox used for pricing/demo requests.
checkpoints.push({ passed: budgetRoutingOk, weight: 0.30 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const automations = JSON.parse(localStorage.getItem('automations') || '[]');
const automationActions = JSON.parse(localStorage.getItem('automation_actions') || '[]');
const conditionGroups = JSON.parse(localStorage.getItem('condition_groups') || '[]');
const conditions = JSON.parse(localStorage.getItem('conditions') || '[]');
const emailTemplates = JSON.parse(localStorage.getItem('email_templates') || '[]');

function findUrgentAutomation() {
  return automations.find(a => {
    if (!a || a.status !== 'active' || a.trigger_type !== 'new_conversation_created') return false;
    const groups = conditionGroups.filter(g => g && g.owner_type === 'automation_rule' && g.owner_id === a.id);
    if (!groups.length) return false;
    let hasEmailChannel = false;
    let hasUrgentTag = false;
    groups.forEach(g => {
      const conds = conditions.filter(c => c && c.owner_type === 'condition_group' && c.owner_id === g.id);
      conds.forEach(c => {
        if (c.field === 'channel' && c.operator === 'equals' && c.value === 'email') {
          hasEmailChannel = true;
        }
        if ((c.field === 'tags' || c.field === 'tag') && c.operator === 'includes' && typeof c.value === 'string' && c.value.toLowerCase() === 'urgent') {
          hasUrgentTag = true;
        }
        if ((c.field === 'tags' || c.field === 'tag') && (c.operator === 'in' || c.operator === 'contains_any_of') && Array.isArray(c.values)) {
          if (c.values.some(v => (v || '').toLowerCase() === 'urgent')) {
            hasUrgentTag = true;
          }
        }
      });
    });
    return hasEmailChannel && hasUrgentTag;
  }) || null;
}

const urgentAutomation = findUrgentAutomation();

// CP1 (0.40): There is an active automation for new conversations with conditions matching channel=email and tag includes 'urgent'.
checkpoints.push({ passed: !!urgentAutomation, weight: 0.40 });

let actionsOk = false;
if (urgentAutomation) {
  const acts = automationActions.filter(a => a && a.automation_rule_id === urgentAutomation.id);
  const waitAction = acts.find(a => a.action_type === 'wait');
  const aiAction = acts.find(a => a.action_type === 'generate_ai_reply');

  if (waitAction && typeof waitAction.delay_minutes === 'number' && waitAction.delay_minutes <= 10 && aiAction) {
    const template = emailTemplates.find(t => t && t.id === aiAction.email_template_id);
    const subject = aiAction.subject_template || '';
    const body = aiAction.body_template || '';
    const sender = aiAction.sender_address || '';

    const subjectOk = subject.startsWith('[URGENT]') && subject.includes('{{ticket_id}}');
    const bodyOk = body.includes('{{customer_first_name}}') && body.includes('{{ticket_id}}');
    const senderOk = sender === 'support@demo-company.test';
    const templateOk = template && template.use_ai_generation === true;
    const sendOk = aiAction.send_without_review === true;
    const orderOk = typeof waitAction.position === 'number' && typeof aiAction.position === 'number' && waitAction.position < aiAction.position;

    actionsOk = subjectOk && bodyOk && senderOk && templateOk && sendOk && orderOk;
  }
}

// CP2 (0.60): The automation waits no more than 10 minutes, then uses an AI urgent acknowledgement template to auto-send a reply from support@demo-company.test with correct subject/body placeholders and no human review, in the correct action order.
checkpoints.push({ passed: actionsOk, weight: 0.60 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const routingRules = JSON.parse(localStorage.getItem('routing_rules') || '[]');
const conditionGroups = JSON.parse(localStorage.getItem('condition_groups') || '[]');
const conditions = JSON.parse(localStorage.getItem('conditions') || '[]');
const inboxes = JSON.parse(localStorage.getItem('inboxes') || '[]');

function analyzeRoutingRule() {
  const rule = routingRules.find(r => r && r.status === 'active' && r.evaluation_event === 'on_first_customer_message' && r.schedule === 'always_on' && r.scope === 'global');
  if (!rule) return { rule: null };

  const groups = conditionGroups.filter(g => g && g.owner_type === 'routing_rule' && g.owner_id === rule.id);
  const lower = s => (s || '').toLowerCase();

  let pricingGroup = null;
  let technicalGroup = null;

  groups.forEach(g => {
    const conds = conditions.filter(c => c && c.owner_type === 'condition_group' && c.owner_id === g.id);
    const kwSet = new Set();
    conds.forEach(c => {
      if (c.field === 'message_text' || c.field === 'first_customer_message_text') {
        if (Array.isArray(c.values)) {
          c.values.forEach(v => kwSet.add(lower(v)));
        } else if (typeof c.value === 'string') {
          kwSet.add(lower(c.value));
        }
      }
    });
    const kws = Array.from(kwSet);
    const hasPricing = ['price','pricing','quote'].every(k => kws.includes(k));
    const hasTechnical = ['bug','error','not working'].every(k => kws.includes(k));
    if (g.logic_within_group === 'or' && hasPricing) pricingGroup = g;
    if (g.logic_within_group === 'or' && hasTechnical) technicalGroup = g;
  });

  return { rule, pricingGroup, technicalGroup };
}

const { rule: routingRule, pricingGroup, technicalGroup } = analyzeRoutingRule();

// CP1 (0.60): An active global routing rule evaluated on first customer message exists, with OR-based condition groups matching pricing keywords and technical issue keywords.
checkpoints.push({ passed: !!routingRule && !!pricingGroup && !!technicalGroup, weight: 0.60 });

let branchesOk = false;
if (routingRule && pricingGroup && technicalGroup) {
  const salesInbox = inboxes.find(i => i && i.name && i.name.toLowerCase() === 'sales');
  const supportInbox = inboxes.find(i => i && i.name && i.name.toLowerCase() === 'support');

  if (salesInbox && supportInbox) {
    const ba = Array.isArray(routingRule.branch_actions) ? routingRule.branch_actions : [];
    const pricingBranch = ba.find(b => b && b.condition_group_id === pricingGroup.id);
    const technicalBranch = ba.find(b => b && b.condition_group_id === technicalGroup.id);

    const pricingOk = pricingBranch && pricingBranch.assign_inbox_id === salesInbox.id && (pricingBranch.priority || 'normal') === 'normal';
    const technicalOk = technicalBranch && technicalBranch.assign_inbox_id === supportInbox.id && technicalBranch.priority === 'high';

    branchesOk = pricingOk && technicalOk;
  }
}

// CP2 (0.40): Branch actions route pricing messages to the Sales inbox with normal priority and technical messages to the Support inbox with high priority.
checkpoints.push({ passed: branchesOk, weight: 0.40 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const reports = JSON.parse(localStorage.getItem('analytics_reports') || '[]');
const conditionGroups = JSON.parse(localStorage.getItem('condition_groups') || '[]');
const conditions = JSON.parse(localStorage.getItem('conditions') || '[]');
const widgets = JSON.parse(localStorage.getItem('dashboard_widgets') || '[]');

const report = reports.find(r => {
  if (!r) return false;
  const nameOk = (r.name || '').toLowerCase() === 'ai resolution - 30 days';
  const typeOk = r.report_type === 'ai_performance';
  const primaryOk = r.primary_metric === 'ai_resolution_rate';
  const dateOk = r.date_range_type === 'last_30_days';
  const groupOk = Array.isArray(r.group_by) && r.group_by.includes('channel');
  const sortOk = r.sort_by_field === 'ai_resolved_conversations' && r.sort_order === 'descending';
  const secondaryOk = Array.isArray(r.secondary_metrics) && r.secondary_metrics.includes('ai_resolved_conversations');
  return nameOk && typeOk && primaryOk && dateOk && groupOk && sortOk && secondaryOk;
}) || null;

// CP1 (0.60): Report 'AI Resolution - 30 days' exists with type ai_performance, primary metric ai_resolution_rate, secondary metric ai_resolved_conversations, last_30_days range, grouped by channel, sorted by ai_resolved_conversations descending.
checkpoints.push({ passed: !!report, weight: 0.60 });

let filterOk = false;
if (report && report.filter_condition_group_id) {
  const g = conditionGroups.find(cg => cg && cg.id === report.filter_condition_group_id && cg.owner_type === 'analytics_report');
  if (g) {
    const conds = conditions.filter(c => c && c.owner_type === 'condition_group' && c.owner_id === g.id);
    filterOk = conds.some(c => {
      if (!c) return false;
      const field = c.field;
      const op = c.operator;
      const valNum = typeof c.value === 'string' ? parseFloat(c.value) : NaN;
      const isCoverageField = field === 'ai_coverage' || field === 'ai_messages_percentage';
      return isCoverageField && op === 'greater_than_or_equal' && !isNaN(valNum) && valNum >= 80;
    });
  }
}

// CP2 (0.25): Report has a filter condition ensuring AI coverage/AI messages percentage is at least 80%.
checkpoints.push({ passed: filterOk, weight: 0.25 });

let pinOk = false;
if (report) {
  const widget = widgets.find(w => w && w.report_id === report.id);
  if (widget && report.is_pinned === true) {
    const rows = widgets.map(w => w.row).filter(r => typeof r === 'number');
    const minRow = rows.length ? Math.min.apply(null, rows) : widget.row;
    pinOk = widget.row === minRow;
  }
}

// CP3 (0.15): Report is pinned to the dashboard and its widget is on the top row.
checkpoints.push({ passed: pinOk, weight: 0.15 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const integrations = JSON.parse(localStorage.getItem('integrations') || '[]');
const mappings = JSON.parse(localStorage.getItem('integration_field_mappings') || '[]');

const crmIntegration = integrations.find(i => i && i.type === 'crm' && i.provider_key === 'demo_crm_sandbox') || null;

const integrationOk = !!crmIntegration &&
  crmIntegration.status === 'connected' &&
  crmIntegration.environment === 'sandbox' &&
  crmIntegration.api_key === 'TEST-1234' &&
  crmIntegration.sync_new_conversations === true &&
  crmIntegration.auto_create_contacts === true;

// CP1 (0.60): Demo CRM sandbox integration (type=crm) is connected with TEST-1234 API key, sandbox environment, and both sync_new_conversations and auto_create_contacts enabled.
checkpoints.push({ passed: integrationOk, weight: 0.60 });

let mappingOk = false;
if (crmIntegration) {
  const crmMaps = mappings.filter(m => m && m.integration_id === crmIntegration.id);

  const emailMap = crmMaps.find(m =>
    m.platform_field === 'Customer email' &&
    m.crm_object_type === 'contact' &&
    m.crm_field === 'Contact Email'
  );

  const nameMap = crmMaps.find(m =>
    m.platform_field === 'Customer full name' &&
    m.crm_object_type === 'contact' &&
    m.crm_field === 'Contact Name'
  );

  const companyMap = crmMaps.find(m =>
    m.platform_field === 'Company name' &&
    m.crm_object_type === 'account' &&
    m.crm_field === 'Account Name'
  );

  mappingOk = !!emailMap && !!nameMap && !!companyMap;
}

// CP2 (0.40): Integration field mappings include customer email→Contact Email, customer full name→Contact Name, and company name→Account Name.
checkpoints.push({ passed: mappingOk, weight: 0.40 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const knowledgeBases = JSON.parse(localStorage.getItem('knowledge_bases') || '[]');
const articlesAll = JSON.parse(localStorage.getItem('knowledge_base_articles') || '[]');
const kbSettingsList = JSON.parse(localStorage.getItem('knowledge_base_settings') || '[]');

const mainKb = knowledgeBases.find(kb => kb && kb.default_visibility === 'public' && kb.is_active && (kb.name || '').toLowerCase().includes('main')) || null;

// CP1 (0.20): A main public active knowledge base exists.
checkpoints.push({ passed: !!mainKb, weight: 0.20 });

let articlesOk = false;
if (mainKb) {
  const articles = articlesAll.filter(a => a && a.knowledge_base_id === mainKb.id && a.visibility === 'public' && a.status === 'published');
  const pricingArt = articles.find(a => (a.title || '').toLowerCase().includes('pricing')) || null;
  const trialArt = articles.find(a => (a.title || '').toLowerCase().includes('trial')) || null;
  const supportArt = articles.find(a => (a.title || '').toLowerCase().includes('support hours')) || null;
  const distinctIds = pricingArt && trialArt && supportArt
    ? new Set([pricingArt.id, trialArt.id, supportArt.id])
    : new Set();
  articlesOk = pricingArt && trialArt && supportArt && distinctIds.size === 3;
}

// CP2 (0.50): Main KB has three distinct public, published FAQ articles whose titles include 'pricing', 'trial', and 'support hours'.
checkpoints.push({ passed: articlesOk, weight: 0.50 });

let settingsOk = false;
if (mainKb) {
  const settings = kbSettingsList.find(s => s && s.knowledge_base_id === mainKb.id) || null;
  settingsOk = !!settings &&
    settings.use_for_ai_answers === true &&
    settings.preferred_source === 'knowledge_base_first_then_history' &&
    settings.apply_to_bots === true;
}

// CP3 (0.30): Main KB is configured for AI answers with preference knowledge_base_first_then_history and applied to bots.
checkpoints.push({ passed: settingsOk, weight: 0.30 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const agents = JSON.parse(localStorage.getItem('agents') || '[]');
const inboxes = JSON.parse(localStorage.getItem('inboxes') || '[]');

const agent = agents.find(a => a && a.email === 'alex.support@example.test' && a.role === 'agent') || null;

// CP1 (0.30): An Agent user with email alex.support@example.test exists.
checkpoints.push({ passed: !!agent, weight: 0.30 });

let accessOk = false;
if (agent) {
  const supportInbox = inboxes.find(i => i && i.name && i.name.toLowerCase() === 'support');
  const assigned = Array.isArray(agent.assigned_inbox_ids) ? agent.assigned_inbox_ids : [];
  const assignedSet = new Set(assigned);
  const onlySupport = !!supportInbox && assignedSet.size === 1 && assignedSet.has(supportInbox.id);
  const perms = Array.isArray(agent.permissions) ? agent.permissions : [];
  accessOk = onlySupport && perms.includes('assigned_inboxes_only');
}

// CP2 (0.40): Agent is assigned only to the Support inbox and has 'assigned_inboxes_only' permission.
checkpoints.push({ passed: accessOk, weight: 0.40 });

let hoursOk = false;
if (agent) {
  const whTypeOk = agent.working_hours_type === 'custom';
  const tzOk = agent.timezone === 'America/New_York';
  const wh = Array.isArray(agent.working_hours) ? agent.working_hours : [];
  const daysNeeded = ['monday','tuesday','wednesday','thursday','friday'];
  const weekdaysOk = daysNeeded.every(d => wh.some(h => h.day_of_week === d && h.start_time === '08:00' && h.end_time === '16:00'));
  const weekendMissing = !wh.some(h => h.day_of_week === 'saturday' || h.day_of_week === 'sunday');
  hoursOk = whTypeOk && tzOk && weekdaysOk && weekendMissing;
}

// CP3 (0.30): Agent has custom working hours set to Monday–Friday 08:00–16:00 in America/New_York, with no Saturday/Sunday hours.
checkpoints.push({ passed: hoursOk, weight: 0.30 });

return checkoints = checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const plans = JSON.parse(localStorage.getItem('pricing_plans') || '[]');
const trials = JSON.parse(localStorage.getItem('trial_signups') || '[]');

const eligiblePlans = plans.filter(p => {
  if (!p) return false;
  if (!p.is_active) return false;
  if (p.billing_type !== 'annual') return false;
  if (!p.includes_ai_assistant) return false;
  if (typeof p.price_per_month !== 'number' || p.price_per_month >= 400) return false;
  if (typeof p.included_seats !== 'number' || p.included_seats < 5) return false;
  return true;
});

let cheapestPlan = null;
if (eligiblePlans.length) {
  cheapestPlan = eligiblePlans.reduce((min, p) => (p.price_per_month < min.price_per_month ? p : min), eligiblePlans[0]);
}

let correctPlanTrial = null;
if (cheapestPlan) {
  correctPlanTrial = trials.find(t => t && t.plan_id === cheapestPlan.id) || null;
}

// CP1 (0.60): A trial has been started for the cheapest annual plan under $400/month that includes AI assistant and at least 5 seats.
const cp1Passed = !!cheapestPlan && !!correctPlanTrial;
checkpoints.push({ passed: cp1Passed, weight: 0.60 });

let formOk = false;
if (correctPlanTrial) {
  const companyNameOk = correctPlanTrial.company_name === 'Example AI Customer Co';
  const companySizeOk = correctPlanTrial.company_size === '51-100 employees';
  const emailOk = correctPlanTrial.email === 'owner@example.test';
  const roleOk = correctPlanTrial.role === 'Owner';
  const aiOk = correctPlanTrial.use_ai_features === true;
  formOk = companyNameOk && companySizeOk && emailOk && roleOk && aiOk;
}

// CP2 (0.40): The trial signup form for that plan was submitted with the exact requested company name, size, email, job title, and AI features enabled.
checkpoints.push({ passed: formOk, weight: 0.40 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
